func encrypt(data: Data, key: CFData) throws -> Data {
    var cryptObj: NCCryptor? = nil

    let options: [NSNumber: AnyObject] = [kCCOptionsPKCS7Padding as NSNumber: true]

    do {
        cryptObj = try NCCryptorCreate(NSCryptDirectionEncode, options as CFDictionary)

        var error: Unmanaged<CFError>?
        let success = cryptObj?.cryptData(data as CFData, iv: nil, inLength: data.count, outLength: nil, outData: nil, key: key, options: options as! [AnyHashable : Any])

        if !success {
            error = cryptObj?.copyValue() as? Unmanaged<CFError>
        }

        guard let error = error else { return data }
        throw EncryptionError.failedEncryption
    } catch {
        cryptObj?.release()
        throw error
    } finally {
        cryptObj?.release()
    }
}

